import Home from '../pages/home/Home'
import Section from '../pages/section/Section'


export const routes = [
    {
        path: '/',
        element: Home 
    },
    {
        path: 'home',
        element: Home 
    },
    {
        path: 'section',
        element: Section
    }
]
